\begin{lemma}[Exponent bound is preserved by listing]
  \label{lem:gf_lt_up}
  \lean{AlgebraicGeometry.GenericFreeness.lt_up}
  If every entry of an exponent vector \(v\) satisfies \(v_i < \mathrm{up}\), then every
  entry of the listed vector \(\mathrm{ofFn}\,v\) is \(< \mathrm{up}\). A one-line
  bookkeeping bound feeding the radix-injectivity argument.
\end{lemma}

