\begin{lemma}[\(\mathrm{finSuccEquiv}\) of a constant-variable inclusion]
  \label{lem:gf_finSuccEquiv_rename_succ}
  \lean{AlgebraicGeometry.GenericFreeness.finSuccEquiv_rename_succ}
  For \(s \in R[X_1, \dots, X_n]\), the composite
  \(R[X_1, \dots, X_n] \xrightarrow{\ \mathrm{rename}\,\mathrm{succ}\ } R[X_0, \dots, X_n]
    \xrightarrow{\ \mathrm{finSuccEquiv}\ } (R[X_1, \dots, X_n])[X_0]\)
  is the coefficient inclusion:
  \(\mathrm{finSuccEquiv}(\mathrm{rename}\,\mathrm{succ}\,s) = \mathrm{C}(s)\). A technical
  compatibility lemma (Mathlib records only the \(\mathrm{optionEquivLeft}\) variant).
\end{lemma}

